print(arr.some((v) => v > 25));
arr.forEach((v, i) => print(v, i));
print(arr.map((v, i) => v + i));
print(arr.mapFiltered((v) => (v > 10 ? v : undefined)));
const sparse: Array<number | undefined> = [10, undefined];
print(sparse.filterUndefined());
